const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const query = String(body.query || '').trim();
if (!query) {
  throw new Error('Missing query');
}
const parsedLimit = Number(body.limit || 8);
const limit = Number.isFinite(parsedLimit) ? Math.max(1, Math.min(12, Math.round(parsedLimit))) : 8;
const searchMode = String(body.mode || 'search').trim().toLowerCase();
return [{ json: { query, limit, mode: searchMode === 'answer' ? 'answer' : 'search' } }];

const request = $items('Normalize Request', 0, 0).json;
const vector = $json.data?.[0]?.embedding;
if (!Array.isArray(vector)) {
  throw new Error('Embedding vector missing in OpenAI response');
}
const prefetchLimit = Math.max(request.limit * 4, 20);
const qdrantBody = {
  prefetch: [
    {
      using: $env.QDRANT_DENSE_VECTOR_NAME || 'dense',
      query: vector,
      limit: prefetchLimit
    },
    {
      using: $env.QDRANT_SPARSE_VECTOR_NAME || 'bm25',
      query: {
        text: request.query,
        model: 'Qdrant/bm25'
      },
      limit: prefetchLimit
    }
  ],
  query: { fusion: 'rrf' },
  limit: request.limit,
  with_payload: true,
  with_vector: false
};
return [{ json: { ...request, qdrantBody } }];

const request = $items('Build Hybrid Query', 0, 0).json;
const points = $json.result?.points || [];
const hits = points.map((point, index) => {
  const payload = point.payload || {};
  const sectionPath = Array.isArray(payload.section_path) ? payload.section_path : [];
  return {
    rank: index + 1,
    score: point.score,
    doc_title: payload.doc_title || null,
    source_file: payload.source_file || null,
    block_type: payload.block_type || null,
    citation: payload.citation || [payload.doc_title, sectionPath.join(' > ')].filter(Boolean).join(' / '),
    section_path: sectionPath,
    raw_text: payload.raw_text || null,
    text: payload.text || null
  };
});
return [{ json: { query: request.query, limit: request.limit, mode: request.mode, count: hits.length, hits } }];
